code = """import json

# Load descriptions
path_tickers = locals()['var_function-call-12166660516732642610']
with open(path_tickers, 'r') as f:
    ticker_data = json.load(f)
descriptions = ticker_data['descriptions']

# Load batch 1
path_batch1 = locals()['var_function-call-10910354273387025755']
with open(path_batch1, 'r') as f:
    results1 = json.load(f)

# Load batch 2
path_batch2 = locals()['var_function-call-15539885544020915063']
with open(path_batch2, 'r') as f:
    results2 = json.load(f)

# Combine
all_results = results1 + results2

# Convert NumDays to int
for r in all_results:
    r['NumDays'] = int(r['NumDays'])

# Sort
sorted_results = sorted(all_results, key=lambda x: x['NumDays'], reverse=True)

# Top 5
top5 = sorted_results[:5]

final_output = []
for item in top5:
    sym = item['Symbol']
    count = item['NumDays']
    desc = descriptions.get(sym, "N/A")
    # Extract Company Name from Description (usually the first sentence or part before " is " or " specializes " etc.)
    # But returning the full description as requested ("list the company names please" - usually implies the name).
    # Looking at the descriptions, they start with the company name.
    # e.g., "AGM Group Holdings Inc. specializes..." -> "AGM Group Holdings Inc."
    # I'll try to extract the name heuristically.
    
    # Heuristic: Split by " is ", " specializes ", " provides ", " operates ", " focuses ".
    separators = [" is ", " specializes ", " provides ", " operates ", " focuses ", " based in ", " was "]
    name = desc
    for sep in separators:
        if sep in name:
            name = name.split(sep)[0]
            break
            
    # Also remove trailing comma if any
    if name.endswith(','):
        name = name[:-1]
        
    final_output.append({"Symbol": sym, "Count": count, "Company Name": name})

print("__RESULT__:")
print(json.dumps(final_output))"""

